import{_ as t,o as r,c as a,ae as s}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Support Guide","description":"","frontmatter":{"title":"Support Guide","slug":"support-guide"},"headers":[],"relativePath":"account-hub/support-guide.md","filePath":"account-hub/support-guide.md"}'),o={name:"account-hub/support-guide.md"};function i(n,e,u,d,l,c){return r(),a("div",null,[...e[0]||(e[0]=[s('<h2 id="submit-a-ticket" tabindex="-1">Submit a ticket <a class="header-anchor" href="#submit-a-ticket" aria-label="Permalink to &quot;Submit a ticket&quot;">​</a></h2><p>To submit a ticket to Branch, visit our <a href="https://support.branch.io/hc/en-us/requests/new" target="_blank" rel="noreferrer">Support portal</a>.</p><p>You&#39;ll be given the option to submit one of the following types of inquiries:</p><ul><li>Technical support.</li><li>Sales.</li><li>Billing.</li></ul><h2 id="service-types" tabindex="-1">Service types <a class="header-anchor" href="#service-types" aria-label="Permalink to &quot;Service types&quot;">​</a></h2><p>Branch offers three types of services to help you make the most of your Branch integration.</p><p>Our customer-facing technical teams can help you build out a new idea, discover how a particular feature can further your campaigns, debug a tricky issue, and much more.</p><h3 id="account-management" tabindex="-1">Account management <a class="header-anchor" href="#account-management" aria-label="Permalink to &quot;Account management&quot;">​</a></h3><p>Account Management Services includes a dedicated team that offers personalized support and product recommendations.</p><p>By embedding Account Management Services into your team, you ensure the right support is available exactly when you need it as your brand grows with Branch.</p><h3 id="professional-services" tabindex="-1">Professional services <a class="header-anchor" href="#professional-services" aria-label="Permalink to &quot;Professional services&quot;">​</a></h3><p>Access to Professional Services lets you lean on our industry experts for complex use cases, integrations, and platform configurations.</p><p>By allocating Professional Service Hours for your team, you&#39;re securing support for your onboarding process, implementation objectives, and team knowledge building goals.</p><h3 id="premium-support" tabindex="-1">Premium support <a class="header-anchor" href="#premium-support" aria-label="Permalink to &quot;Premium support&quot;">​</a></h3><p>Rely on our Premium Support Services to resolve your concerns quickly. Response times are as fast as 2 hours, <strong>even on weekends</strong>.</p><p>Our Premium Support Service hours follow a fixed pricing model, which offers more predictability and reliability as you plan for your team&#39;s ongoing needs.</p><h3 id="standard-support" tabindex="-1">Standard support <a class="header-anchor" href="#standard-support" aria-label="Permalink to &quot;Standard support&quot;">​</a></h3><p>Standard Support is available to answer questions via email <strong>during business hours only</strong>.</p><p>Business hours vary depending on the timezone.</p><p>Our business hours are listed below:</p><ul><li><strong>ANZ</strong> Business Hours: 9 AM - 5 PM (Sydney Time)</li><li><strong>NEA</strong> Business Hours: 9 AM - 5 PM (Seoul Time)</li><li><strong>SEA</strong> Business Hours: 9 AM - 5 PM (Singapore Time)</li><li><strong>India</strong> Business Hours: 9 AM - 5 PM (Bangalore Time)</li><li><strong>EMEA</strong> Business Hours: 9 AM - 5 PM (London Time)</li><li><strong>NA</strong> Business Hours: 9 AM - 5 PM (Pacific Time US &amp; Canada)</li></ul><h2 id="slas" tabindex="-1">SLAs <a class="header-anchor" href="#slas" aria-label="Permalink to &quot;SLAs&quot;">​</a></h2><p>Our Response Time Service Level Agreements (SLAs) are defined by your package and are subject to change. Branch&#39;s current initial response SLAs can be found below:</p><table tabindex="0"><thead><tr><th>Severity Level</th><th>Definition</th><th>Standard Support</th><th>Enhanced Support</th><th>Premium Support</th></tr></thead><tbody><tr><td>Sev 0 - Outage</td><td>A service outage of Branch systems that would impact link redirection or attribution.</td><td>2 Hours</td><td>1 Hour</td><td>1 Hour</td></tr><tr><td>Sev 1 - High</td><td>The Services are completely unavailable for use by Customer, and no procedural workaround exists, thereby causing a severe impact to Customer&#39;s business operations.</td><td>1 Business Day</td><td>4 hours</td><td>2 hours</td></tr><tr><td>Sev 2 - Medium</td><td>Customer experiences a severe defect or configuration issue with the use of the Services and no procedural workaround exists, thereby causing a high impact to Customer&#39;s business operations (excluding Service failures that qualify as Severity Level High).</td><td>2 Business Days</td><td>8 hours</td><td>4 hours</td></tr><tr><td>Sev 3 - Low</td><td>Customer experiences an issue where Customer&#39;s use of the Services are partially reduced, thereby causing a low-to-medium impact to Customer&#39;s business operations. A procedural workaround exists (excluding Service issues that qualify as Severity Level High or Medium).</td><td>5 Business Days</td><td>1 Business Day</td><td>8 hours</td></tr></tbody></table><p>Note that SLA times do <strong>not</strong> apply to self-serve customers.</p><h2 id="best-practices" tabindex="-1">Best practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best practices&quot;">​</a></h2><p>Below are some best practices when reporting an issue.</p><ul><li>Include your Branch App ID with your support ticket. You can find your App ID in <a href="https://dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">Branch</a> by navigating to <strong>Account Settings &gt; Profile</strong>.</li><li>Include steps to reproduce the issue, error messages, and any screenshots whenever applicable to help us expedite our investigation.</li><li>If you&#39;re an Ad Partner or an Agency reaching out to us about a specific campaign, provide us with the tracking link and details about the campaign/customer app.</li><li>If the issue is related to your app code, send us code snippets whenever applicable.</li><li>When reporting a new issue, start a new email thread; using an old email thread for a different ticket could delay response.</li><li>Reply to the auto-response you receive when a new ticket is created to add additional information to the ticket.</li></ul>',28)])])}const m=t(o,[["render",i]]);export{h as __pageData,m as default};
